sql:
SELECT idea_id
FROM idea_wins
WHERE wins = (SELECT MAX(wins) FROM idea_wins);

SELECT COUNT(*) AS total_user_submitted_ideas
FROM ideas
WHERE user_submitted = 1;

SELECT wikisurvey_name
FROM wikisurveys
WHERE active = 1;

SELECT COUNT(*) AS idea_count
FROM ideas_categories
WHERE category_id = 1;

SELECT COUNT(*) 
FROM wikisurveys 
WHERE active = 1;

SELECT idea_id, SUM(undecided_count) AS total_undecideds
FROM idea_undecideds
GROUP BY idea_id;

SELECT AVG(score) AS average_score
FROM idea_scores
WHERE score_method = 'Elo rating';

external_knowledge:
- "Popular ideas" refers to ideas with more than 5 wins; 
- "Frequently interacted" means the total number of interactions involving the idea is more than 0; 
- "Successful ideas" refers to wins > 5; 
- "Made a significant impact" refers to average appearances on the left or right being greater than 10.

sql:
SELECT total_interactions AS total_interactions_for_idea
FROM idea_appearances
WHERE idea_id = 1;
